#include <iostream>
#include <string>
#include <stdexcept>

class Date {
private:
    int day;
    int month;
    int year;

    bool is_leap(int y) const {
        return (y % 4 == 0 && y % 100 != 0) || (y % 400 == 0);
    }

    bool is_valid_date(int d, int m, int y) const {
        if (y < 1) return false;
        if (m < 1 || m > 12) return false;

        int days_in_month[] = {0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31};
        if (is_leap(y)) {
            days_in_month[2] = 29;
        }

        if (d < 1 || d > days_in_month[m]) return false;
        return true;
    }

public:
    Date(int d, int m, int y) {
        if (!is_valid_date(d, m, y)) {
            throw std::invalid_argument("Invalid date provided. Day, month, or year out of range.");
        }
        this->day = d;
        this->month = m;
        this->year = y;
    }

    bool operator==(const Date& other) const {
        return day == other.day && month == other.month && year == other.year;
    }

    void print() const {
        std::cout << day << "/" << month << "/" << year;
    }
};

int main() {
    try {
        Date d1(15, 7, 2025);
        Date d2(15, 7, 2025);
        Date d3(16, 7, 2025);
        Date d4(29, 2, 2024);

        std::cout << (d1 == d2 ? "true" : "false") << std::endl;
        std::cout << (d1 == d3 ? "true" : "false") << std::endl;
        std::cout << (d4 == d4 ? "true" : "false") << std::endl;

        // This will throw an exception, so it's handled in the driver for expected output
        try {
            Date invalid_date(29, 2, 2023); // 2023 is not a leap year
            std::cout << "true" << std::endl; // Should not be reached
        } catch (const std::invalid_argument& e) {
            std::cerr << "Error: " << e.what() << std::endl;
        }

    } catch (const std::invalid_argument& e) {
        // Catching any initial invalid date creation in main
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
